/**
 * @munesoft/objx — path utilities
 * High-performance path tokenizer with compiled path cache.
 */
/** A single parsed segment of a dot/bracket path */
export type Segment = string | number;
/** Compiled getter function for hot-path reuse */
export type CompiledGetter<T = unknown> = (obj: unknown) => T | undefined;
/** Returns true if the key is a dangerous prototype key */
export declare function isBlockedKey(key: string): boolean;
/**
 * Parses a path string into an array of segments.
 * Supports:
 *   - dot notation: "a.b.c"
 *   - bracket notation: "a[0].b"
 *   - mixed:         "users[2].profile.name"
 *
 * Results are cached for repeat calls.
 */
export declare function parsePath(path: string): Segment[];
/** Clears the internal path cache (useful for testing) */
export declare function clearPathCache(): void;
